<script setup lang="ts">
/**
 * 登录 / 注册页
 * - 背景:login.png
 * - tab 切换 登录 / 注册
 * - 错误提示来自后端业务码(账号不存在 / 密码错误 / 账号已存在 ...)
 * - 登录成功 → router.replace(redirect || '/')
 * - 12h token 由后端签发,前端 store 校验过期
 */
import { ref, computed } from 'vue'
import { useRouter, useRoute } from 'vue-router'
import { useUserStore, authErrorMessage } from '@/stores/user'

type Mode = 'login' | 'register'

const router = useRouter()
const route = useRoute()
const userStore = useUserStore()

const mode = ref<Mode>('login')
const account = ref('')
const password = ref('')
const confirm = ref('')
const errorMsg = ref('')
const submitting = ref(false)

const isLogin = computed(() => mode.value === 'login')
const submitLabel = computed(() => (isLogin.value ? '登 录' : '注 册'))

function clearError() {
  errorMsg.value = ''
}

function switchMode(m: Mode) {
  mode.value = m
  clearError()
  password.value = ''
  confirm.value = ''
}

function validate(): string | null {
  const acc = account.value.trim()
  if (acc.length < 3 || acc.length > 20) return '账号长度需 3-20 字符'
  if (!/^[a-zA-Z0-9_]+$/.test(acc)) return '账号仅支持字母数字下划线'
  if (password.value.length < 6 || password.value.length > 32) return '密码长度需 6-32 字符'
  if (!isLogin.value && password.value !== confirm.value) return '两次输入的密码不一致'
  return null
}

async function handleSubmit() {
  clearError()
  const v = validate()
  if (v) {
    errorMsg.value = v
    return
  }
  submitting.value = true
  try {
    const payload = { account: account.value.trim(), password: password.value }
    const r = isLogin.value
      ? await userStore.loginWith(payload)
      : await userStore.registerWith(payload)
    if (!r.ok) {
      // 兜底文案绝不回退到 axios 默认(可能带英文/状态码/不友好)
      errorMsg.value = authErrorMessage(r.code, r.message)
      return
    }
    // 成功 → 跳到 redirect 或首页
    const redirect = (route.query.redirect as string | undefined) ?? '/'
    router.replace(redirect)
  } finally {
    submitting.value = false
  }
}
</script>

<template>
  <div
    class="relative min-h-screen w-full flex items-center justify-center overflow-hidden bg-black"
  >
    <!-- 背景图 -->
    <div
      class="absolute inset-0 bg-cover bg-center"
      :style="{
        backgroundImage: 'url(/assets/bg/login.png)',
        filter: 'brightness(0.55) saturate(1.1)',
      }"
    />
    <!-- 暗化蒙层 -->
    <div class="absolute inset-0 bg-gradient-to-b from-black/50 via-black/30 to-black/70" />

    <!-- 登录卡片 -->
    <div
      class="relative z-10 w-[420px] max-w-[92vw] rounded-2xl overflow-hidden border-2 border-amber-700/60 shadow-2xl text-white"
      style="background: rgba(15, 12, 8, 0.5); backdrop-filter: blur(6px)"
    >
      <!-- 标题 -->
      <div class="px-6 pt-6 pb-2 text-center">
        <h1 class="text-3xl font-black tracking-widest text-amber-200 drop-shadow">子夜大乐斗</h1>
        <p class="text-amber-200/60 text-[12px] mt-1">江湖路远,先登录再启程</p>
      </div>

      <!-- Tab 切换 -->
      <div class="flex mx-6 mt-2 border-b border-amber-700/40">
        <button
          type="button"
          class="flex-1 py-2 text-[14px] font-bold transition border-b-2 -mb-px"
          :class="
            isLogin
              ? 'text-amber-200 border-amber-300'
              : 'text-amber-200/50 border-transparent hover:text-amber-200/80'
          "
          @click="switchMode('login')"
        >
          登 录
        </button>
        <button
          type="button"
          class="flex-1 py-2 text-[14px] font-bold transition border-b-2 -mb-px"
          :class="
            !isLogin
              ? 'text-amber-200 border-amber-300'
              : 'text-amber-200/50 border-transparent hover:text-amber-200/80'
          "
          @click="switchMode('register')"
        >
          注 册
        </button>
      </div>

      <!-- 表单 -->
      <form class="px-6 pt-5 pb-6 space-y-3" @submit.prevent="handleSubmit">
        <!-- 账号 -->
        <div>
          <label class="block text-[12px] text-amber-200/70 mb-1">账号</label>
          <input
            v-model="account"
            type="text"
            autocomplete="username"
            placeholder="3-20 字符,字母数字下划线"
            maxlength="20"
            :disabled="submitting"
            class="w-full px-3 py-2 rounded bg-black/50 border border-amber-700/40 text-amber-100 placeholder-amber-200/30 outline-none focus:border-amber-400 transition disabled:opacity-50"
            @input="clearError"
          />
        </div>
        <!-- 密码 -->
        <div>
          <label class="block text-[12px] text-amber-200/70 mb-1">密码</label>
          <input
            v-model="password"
            type="password"
            :autocomplete="isLogin ? 'current-password' : 'new-password'"
            placeholder="6-32 字符"
            maxlength="32"
            :disabled="submitting"
            class="w-full px-3 py-2 rounded bg-black/50 border border-amber-700/40 text-amber-100 placeholder-amber-200/30 outline-none focus:border-amber-400 transition disabled:opacity-50"
            @input="clearError"
          />
        </div>
        <!-- 确认密码(仅注册) -->
        <div v-if="!isLogin">
          <label class="block text-[12px] text-amber-200/70 mb-1">确认密码</label>
          <input
            v-model="confirm"
            type="password"
            autocomplete="new-password"
            placeholder="再输一次"
            maxlength="32"
            :disabled="submitting"
            class="w-full px-3 py-2 rounded bg-black/50 border border-amber-700/40 text-amber-100 placeholder-amber-200/30 outline-none focus:border-amber-400 transition disabled:opacity-50"
            @input="clearError"
          />
        </div>

        <!-- 错误提示(明显的红色横幅 + shake 动画) -->
        <div
          v-if="errorMsg"
          class="px-3 py-2.5 rounded-lg text-[13px] font-bold text-white bg-gradient-to-r from-rose-700 to-rose-600 border-2 border-rose-400 shadow-lg shadow-rose-900/60 flex items-center gap-2 animate-shake"
          role="alert"
        >
          <span class="text-[18px]">⚠️</span>
          <span class="flex-1">{{ errorMsg }}</span>
          <button
            type="button"
            class="text-rose-100/80 hover:text-white text-[16px] leading-none"
            aria-label="关闭提示"
            @click="clearError"
          >
            ✕
          </button>
        </div>

        <!-- 提交 -->
        <button
          type="submit"
          :disabled="submitting"
          class="w-full py-2.5 rounded-lg bg-gradient-to-r from-amber-500 to-orange-500 hover:from-amber-400 hover:to-orange-400 text-slate-900 font-black text-[15px] tracking-widest shadow-lg transition active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
        >
          <span
            v-if="submitting"
            class="inline-block w-4 h-4 border-2 border-slate-900/30 border-t-slate-900 rounded-full animate-spin"
          />
          <span>{{ submitting ? '处理中...' : submitLabel }}</span>
        </button>

        <!-- 底部提示 -->
        <p class="text-center text-[11px] text-amber-200/40">
          {{ isLogin ? '没有账号?点上方「注册」' : '已有账号?点上方「登录」' }}
        </p>
      </form>
    </div>
  </div>
</template>
